// Prepare CRM data for Salesforce upsert
const item = $input.first().json;

// Extract clean email from "Name <email>" format or object
let cleanEmail = item.sender_email || '';
if (typeof cleanEmail === 'object') {
  cleanEmail = cleanEmail.email || cleanEmail.address || JSON.stringify(cleanEmail);
}
cleanEmail = String(cleanEmail);
const emailMatch = cleanEmail.match(/<([^>]+)>/);
if (emailMatch) cleanEmail = emailMatch[1];
else if (cleanEmail.includes('@')) cleanEmail = cleanEmail.trim();

// Split contact name into first + last
const fullName = String(item.contact_name || '').trim();
const nameParts = fullName.split(/\s+/).filter(Boolean);
const firstName = nameParts.length > 1 ? nameParts.slice(0, -1).join(' ') : (nameParts[0] || '');
const lastName = nameParts.length > 1 ? nameParts[nameParts.length - 1] : (nameParts[0] || 'Unknown');

// Map sentiment to Salesforce Lead Rating
const ratingMap = { Positive: 'Hot', Neutral: 'Warm', Negative: 'Cold' };

// Determine if Opportunity should be created (hot leads only)
const urgency = Number(item.urgency_score) || 0;
const budgetMentioned = item.budget_mentioned === 'true';
const createOpportunity = (item.sentiment === 'Positive' && urgency >= 7) || budgetMentioned;

return [{
  json: {
    // Standard Lead fields
    email: cleanEmail,
    firstName: firstName,
    lastName: lastName,
    company: String(item.org_name || item.sender_domain || 'Unknown'),
    leadRating: ratingMap[item.sentiment] || 'Warm',
    description: String(item.suggested_action || ''),
    // Custom fields for Salesforce
    sentiment: String(item.sentiment || 'Unknown'),
    sentimentConfidence: String(item.confidence || 'N/A'),
    primaryTopic: String(item.primary_topic || ''),
    leadIntent: String(item.intent || ''),
    urgencyScore: urgency,
    budgetMentioned: budgetMentioned,
    eventReferenced: String(item.event_referenced || ''),
    emailDomain: String(item.sender_domain || ''),
    lastEmailSubject: String(item.subject || ''),
    suggestedAction: String(item.suggested_action || ''),
    // Opportunity control flags
    createOpportunity: createOpportunity,
    opportunityName: createOpportunity
      ? (item.primary_topic || 'Inquiry') + ' — ' + (item.org_name || cleanEmail) + ' (Week ' + (item.week_number || '') + ')'
      : ''
  }
}];

// Prepare analytics row from enriched email data
// $input comes from Extract Email Intelligence
const item = $input.first().json;

// Sentiment data — try direct property first, then upstream node reference
let sentimentCategory = 'Unknown';
let sentimentConfidence = 'N/A';
try {
  if (item.sentimentAnalysis) {
    sentimentCategory = item.sentimentAnalysis.category || 'Unknown';
    sentimentConfidence = String(item.sentimentAnalysis.confidence || 'N/A');
  } else {
    const sentimentNode = $('Analyze Email Sentiment1').first().json;
    sentimentCategory = sentimentNode.sentimentAnalysis?.category || 'Unknown';
    sentimentConfidence = String(sentimentNode.sentimentAnalysis?.confidence || 'N/A');
  }
} catch (e) {
  // Fallback — sentiment data not available
}

// Gmail data — handle from field as string OR object
let fromField = '';
let subject = '';
try {
  // Try to get from the input item first
  let rawFrom = item.from || null;
  let rawSubject = item.subject || '';

  // If not on input, try the Get Full Email node
  if (!rawFrom) {
    const gmail = $('Get Full Email4').first().json;
    rawFrom = gmail.from || '';
    rawSubject = gmail.subject || '';
  }

  // Handle from field: could be string "Name <email>" or object {name, email}
  if (typeof rawFrom === 'object' && rawFrom !== null) {
    // Object format: {name: "John Doe", email: "user@example.com"}
    if (rawFrom.email) {
      fromField = rawFrom.name ? `${rawFrom.name} <${rawFrom.email}>` : rawFrom.email;
    } else if (rawFrom.value && Array.isArray(rawFrom.value)) {
      // Some email parsers return {value: [{address: "...", name: "..."}]}
      const first = rawFrom.value[0];
      fromField = first ? (first.name ? `${first.name} <${first.address}>` : first.address || '') : '';
    } else {
      fromField = JSON.stringify(rawFrom);
    }
  } else {
    fromField = String(rawFrom || '');
  }

  subject = String(rawSubject || '');
} catch (e) {
  // Fallback — gmail data not available
}

// Extract domain from email — fromField is guaranteed to be a string now
const domainMatch = fromField.match(/@([^>\s]+)/);

return [{
  json: {
    timestamp: new Date().toISOString(),
    sentiment: sentimentCategory,
    confidence: sentimentConfidence,
    sender_email: fromField,
    sender_domain: domainMatch ? domainMatch[1] : '',
    subject: subject,
    primary_topic: String(item.primary_topic || item.output?.primary_topic || ''),
    secondary_topics: String(item.secondary_topics || item.output?.secondary_topics || ''),
    intent: String(item.intent || item.output?.intent || ''),
    urgency_score: Number(item.urgency_score || item.output?.urgency_score || 0),
    org_name: String(item.org_name || item.output?.org_name || ''),
    contact_name: String(item.contact_name || item.output?.contact_name || ''),
    budget_mentioned: String(item.budget_mentioned ?? item.output?.budget_mentioned ?? false),
    event_referenced: String(item.event_referenced || item.output?.event_referenced || ''),
    suggested_action: String(item.suggested_action || item.output?.suggested_action || ''),
    week_number: getWeekNumber(new Date())
  }
}];

function getWeekNumber(d) {
  const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  const dayNum = date.getUTCDay() || 7;
  date.setUTCDate(date.getUTCDate() + 4 - dayNum);
  const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
  return Math.ceil((((date - yearStart) / 86400000) + 1) / 7);
}

const item = $input.first().json;
let parsed = {};
try {
  parsed = JSON.parse(item.output);
} catch (e) {
  parsed = { existsInSalesforce: false, matchedIn: [], reason: 'Failed to parse agent output: ' + String(item.output) };
}

// Haal originele CRM-data op uit Prepare CRM Data4
let crmData = {};
try {
  crmData = $('Prepare CRM Data3').first().json;
} catch (e) {
  // Fallback als node niet beschikbaar is
}

// Merge: CRM-velden eerst, daarna SF check resultaten (zodat SF resultaten nooit overschreven worden)
return [{ json: { ...crmData, ...parsed } }];

const input = $input.first().json;

// Normalize incoming save payload from dashboard so downstream CRM nodes can use stable fields.
return [{
  json: {
    ...input,
    save_source: 'dashboard',
    save_received_at: new Date().toISOString(),
  }
}];
